// Prepare content for review
const confluencePageId = $json['Confluence Page ID'] || $json.confluencePageId || '';
const rawContent = $json['Raw Content'] || $json.rawContent || '';
const contentType = $json['Content Type'] || $json.contentType || 'general';
const focusAreas = $json['Focus Areas'] || $json.focusAreas || '';

// Determine content source
let contentToReview = '';
let contentSource = '';

if (rawContent.trim()) {
  contentToReview = rawContent;
  contentSource = 'raw-input';
} else if (confluencePageId.trim()) {
  // Note: Confluence content would need to be fetched.
  // For now, pass the page ID and note it in the prompt.
  contentToReview = `[Content from Confluence Page ID: ${confluencePageId} — if this was not pre-fetched, the reviewer will note that the content needs to be provided]`;
  contentSource = `confluence:${confluencePageId}`;
} else {
  contentToReview = 'ERROR: No content provided. Please provide either a Confluence Page ID or paste raw content.';
  contentSource = 'none';
}

const contentTypeContext = {
  'linkedin-post': 'LinkedIn post (150-250 words, strong hook, 3-5 hashtags, scannable with line breaks)',
  'blog-article': 'Blog article (800-1200 words, SEO headings, practical takeaways, clear CTAs)',
  'email-copy': 'Marketing email (subject under 50 chars, 250-400 words, single CTA, mobile-friendly)',
  'website-copy': 'Website copy (concise, benefit-led, clear hierarchy, conversion-focused)',
  'social-caption': 'Social media caption (punchy, platform-appropriate, hashtags)',
  'press-release': 'Press release (inverted pyramid, quotes, boilerplate, newswire-ready)',
  'general': 'General marketing content'
};

const systemPrompt = `You are a senior content editor and brand guardian for Meshwork.\n\n## Brand Voice Rules\n- Clear, confident, warm, action-oriented\n- Practitioner tone — write as someone who works in compliance, not a vendor\n- UK English ALWAYS: defence (not defense), organisation (not organization), behaviour (not behavior), recognise (not recognize), colour (not color), licence (not license for noun), centre (not center)\n- Active voice preferred over passive\n- Specific claims backed by data (410+ controls, 70% evidence reuse, 6 frameworks)\n- No jargon without explanation\n- No generic marketing fluff\n\n## Product Context\n- Meshwork: Multi-framework compliance platform for UK SMEs\n- Frameworks: Def Stan 05-138, ISO 27001, SOC 2, IASME Governance, Cyber Essentials, DCC (L0-L3)\n- Target: UK SMEs (10-100 employees) in defence supply chain\n- DEFCON 658 makes DCC mandatory for MOD suppliers\n\n## Content Type: ${contentTypeContext[contentType] || contentTypeContext['general']}\n\n## Review Approach\nProvide a structured review with:\n1. **Overall Assessment** — quality score (1-10) and one-line verdict\n2. **UK English Corrections** — any American spellings or non-UK conventions\n3. **Brand Voice Issues** — deviations from Meshwork tone\n4. **Content Structure** — improvements for the specific content type\n5. **Factual Accuracy** — any incorrect claims about frameworks/regulations\n6. **Suggested Rewrites** — improved versions of weak sections\n7. **Final Polished Version** — the complete content rewritten with all fixes applied`;

const userPrompt = `Review and improve the following ${contentTypeContext[contentType] || 'marketing content'}.\n${focusAreas ? '\nPay special attention to: ' + focusAreas + '\n' : ''}\n---\nCONTENT TO REVIEW:\n\n${contentToReview}\n---\n\nProvide your structured review following the format specified in your instructions.`;

return [{
  json: {
    confluencePageId,
    contentType,
    contentSource,
    focusAreas,
    systemPrompt,
    userPrompt
  }
}];

// Parse GLM-5 review response
const response = $input.item.json;
const contentType = $('Build Review Prompt').item.json.contentType;
const contentSource = $('Build Review Prompt').item.json.contentSource;

let reviewContent = '';
if (response.content && Array.isArray(response.content)) {
  reviewContent = response.content
    .filter(block => block.type === 'text')
    .map(block => block.text)
    .join('\n');
} else if (typeof response === 'string') {
  reviewContent = response;
}

const inputTokens = response.usage?.input_tokens || 0;
const outputTokens = response.usage?.output_tokens || 0;

// Try to extract the quality score from the review
const scoreMatch = reviewContent.match(/(?:quality score|score)[:\s]*([\d.]+)\s*\/\s*10/i) ||
                   reviewContent.match(/([\d.]+)\s*\/\s*10/i);
const qualityScore = scoreMatch ? scoreMatch[1] : 'N/A';

const notificationText = `*Content Review Complete*\nType: ${contentType} | Source: ${contentSource}\nQuality Score: ${qualityScore}/10\nTokens: ${inputTokens} in / ${outputTokens} out\n\n${reviewContent.substring(0, 3500)}${reviewContent.length > 3500 ? '\n\n_[Truncated — full review available in workflow execution]_' : ''}`;

return [{
  json: {
    contentType,
    contentSource,
    qualityScore,
    reviewContent,
    inputTokens,
    outputTokens,
    notificationText
  }
}];
